 29→/**
 30→ * Check if telemetry is enabled.
 31→ *
 32→ * Check order (first match wins):
 33→ * 1. CODE_INSIGHTS_TELEMETRY_DISABLED=1 env var — respects CI/automation opt-out
 34→ * 2. DO_NOT_TRACK=1 env var — respects the community standard
 35→ * 3. config.telemetry field — user's explicit preference
 36→ * 4. Default: true (opt-out model)
 37→ */
 38→export function isTelemetryEnabled(): boolean {
 39→  if (process.env.CODE_INSIGHTS_TELEMETRY_DISABLED === '1') return false;
 40→  if (process.env.DO_NOT_TRACK === '1') return false;
 41→
 42→  const config = loadConfig();
 43→  // If explicitly set in config, respect it
 44→  if (config !== null && typeof config.telemetry === 'boolean') {
 45→    return config.telemetry;
 46→  }
 47→
 48→  // Default: enabled (opt-out model)
 49→  return true;
 50→}
