 52→/**
 53→ * Show the one-time telemetry disclosure notice if it hasn't been shown yet.
 54→ *
 55→ * Uses a touch file at ~/.code-insights/.telemetry-notice-shown to track state.
 56→ * Only displays if telemetry is currently enabled — no point disclosing disabled telemetry.
 57→ *
 58→ * Returns true if the notice was shown, false if it was already shown or telemetry is off.
 59→ */
 60→export function showTelemetryNoticeIfNeeded(): boolean {
 61→  if (!isTelemetryEnabled()) return false;
 62→  if (fs.existsSync(NOTICE_FILE)) return false;
 63→
 64→  // Show the disclosure banner
 65→  console.log('');
 66→  console.log('  Code Insights collects anonymous usage data to improve the CLI.');
 67→  console.log('  Includes: command name, OS, CLI version, AI tool types.');
 68→  console.log('  Never includes: file paths, project names, session content, or personal data.');
 69→  console.log('');
 70→  console.log('  Disable: code-insights telemetry disable');
 71→  console.log('  Details: code-insights telemetry status');
 72→  console.log('');
 73→
 74→  // Mark notice as shown — best-effort write, ignore failures
 75→  try {
 76→    // Ensure config dir exists before writing touch file
 77→    const configDir = getConfigDir();
 78→    if (!fs.existsSync(configDir)) {
 79→      fs.mkdirSync(configDir, { recursive: true, mode: 0o700 });
 80→    }
 81→    fs.writeFileSync(NOTICE_FILE, '', { encoding: 'utf-8', mode: 0o600 });
 82→  } catch {
 83→    // Non-fatal — if we can't write the touch file, we'll show the notice again
 84→    // next time. That's acceptable; we don't want to break the CLI over this.
 85→  }
 86→
 87→  return true;
 88→}
