 90→/**
 91→ * Fire-and-forget telemetry event. Does NOT block the calling command.
 92→ *
 93→ * Design principles:
 94→ * - Never awaited: the caller doesn't wait for this
 95→ * - 2s AbortController timeout: we don't hang if the endpoint is slow
 96→ * - Swallows ALL errors: network failures, JSON errors, anything — telemetry
 97→ *   must never cause a CLI command to fail
 98→ * - No retries: if it fails, it fails. Reliability of individual events
 99→ *   matters less than not disrupting the user's workflow.
100→ */
101→export function trackEvent(command: string, success: boolean, subcommand?: string): void {
102→  if (!isTelemetryEnabled()) return;
103→
104→  // Build the event synchronously — filesystem reads happen here
105→  let event: TelemetryEvent;
106→  try {
107→    event = buildEvent(command, success, subcommand);
108→  } catch {
109→    // If building the event fails (e.g., filesystem read error), silently skip
110→    return;
111→  }
112→
113→  // Fire-and-forget: intentionally not awaited
114→  // The void cast suppresses the "floating promise" lint warning
115→  void sendEvent(event);
116→}
