130→/**
131→ * Build a TelemetryEvent with all fields populated.
132→ * Separated from sendEvent so buildEventPreview can reuse it without sending.
133→ */
134→function buildEvent(command: string, success: boolean, subcommand?: string): TelemetryEvent {
135→  return {
136→    machineId: getMachineId(),
137→    command,
138→    subcommand,
139→    success,
140→    cliVersion: getCliVersion(),
141→    nodeVersion: process.version.replace('v', ''),
142→    os: process.platform,
143→    arch: process.arch,
144→    providers: detectProviders(),
145→    sessionCountBucket: getSessionCountBucket(),
146→    dataSource: getDataSource(),
147→    hasHook: detectHook(),
148→    // Day precision only — avoids time-of-day behavioral fingerprinting
149→    timestamp: new Date().toISOString().slice(0, 10),
150→  };
151→}
