153→/**
154→ * Anonymous machine ID, rotated monthly.
155→ *
156→ * Format: SHA-256(hostname:username:code-insights-YYYY-MM).slice(0, 16)
157→ *
158→ * Monthly rotation ensures:
159→ * - Long-term tracking is not possible across months
160→ * - Events within a month can be correlated for "unique users" metrics
161→ * - No PII: hostname and username are never sent, only their hash
162→ */
163→function getMachineId(): string {
164→  const now = new Date();
165→  // YYYY-MM format for monthly rotation
166→  const monthSalt = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
167→
168→  let username: string;
169→  try {
170→    username = os.userInfo().username;
171→  } catch {
172→    // os.userInfo() throws in Docker/CI when UID has no /etc/passwd entry
173→    username = `uid-${process.getuid?.() ?? 'unknown'}`;
174→  }
175→
176→  const input = [os.hostname(), username, `code-insights-${monthSalt}`].join(':');
177→
178→  return crypto.createHash('sha256').update(input).digest('hex').slice(0, 16);
179→}
