181→/**
182→ * Read CLI version from package.json.
183→ * Uses createRequire for JSON imports since this is ESM and JSON imports
184→ * have inconsistent support across Node versions and bundlers.
185→ */
186→function getCliVersion(): string {
187→  try {
188→    const require = createRequire(import.meta.url);
189→    // package.json is two levels up from src/utils/ -> src/ -> cli/
190→    const pkg = require('../../package.json') as { version: string };
191→    return pkg.version;
192→  } catch {
193→    return 'unknown';
194→  }
195→}
