197→/**
198→ * Detect which AI coding tool data directories exist on this machine.
199→ * We check for the existence of known directories — we never read their contents.
200→ *
201→ * Returns only the tools that are actually present. This tells us which tools
202→ * users are running alongside code-insights, helping us prioritize provider support.
203→ */
204→function detectProviders(): string[] {
205→  const home = os.homedir();
206→  const detected: string[] = [];
207→
208→  // Claude Code: ~/.claude/projects/
209→  if (fs.existsSync(path.join(home, '.claude', 'projects'))) {
210→    detected.push('claude-code');
211→  }
212→
213→  // Cursor: workspace storage directory (cross-platform path)
214→  const cursorStoragePaths = [
215→    // macOS
216→    path.join(home, 'Library', 'Application Support', 'Cursor', 'User', 'workspaceStorage'),
217→    // Linux
218→    path.join(home, '.config', 'Cursor', 'User', 'workspaceStorage'),
219→    // Windows
220→    path.join(home, 'AppData', 'Roaming', 'Cursor', 'User', 'workspaceStorage'),
221→  ];
222→  if (cursorStoragePaths.some((p) => fs.existsSync(p))) {
223→    detected.push('cursor');
224→  }
225→
226→  // Codex CLI: ~/.codex/sessions
227→  if (fs.existsSync(path.join(home, '.codex', 'sessions'))) {
228→    detected.push('codex-cli');
229→  }
230→
231→  // GitHub Copilot CLI: ~/.copilot/session-state
232→  if (fs.existsSync(path.join(home, '.copilot', 'session-state'))) {
233→    detected.push('copilot-cli');
234→  }
235→
236→  return detected;
237→}
