239→/**
240→ * Count .jsonl files under ~/.claude/projects/ and bucket the count.
241→ *
242→ * Buckets are intentionally coarse — we want to understand "heavy vs light"
243→ * usage without counting exact files, which could vary wildly and feels more
244→ * private than a range.
245→ */
246→function getSessionCountBucket(): string {
247→  try {
248→    const claudeDir = getClaudeDir();
249→    if (!fs.existsSync(claudeDir)) return '0';
250→
251→    // Count all .jsonl files recursively under the Claude projects directory
252→    let count = 0;
253→    const walk = (dir: string): void => {
254→      const entries = fs.readdirSync(dir, { withFileTypes: true });
255→      for (const entry of entries) {
256→        if (entry.isDirectory()) {
257→          walk(path.join(dir, entry.name));
258→        } else if (entry.name.endsWith('.jsonl')) {
259→          count++;
260→        }
261→      }
262→    };
263→    walk(claudeDir);
264→
265→    // Coarse buckets for privacy — exact session counts are never sent
266→    if (count === 0) return '0';
267→    if (count <= 10) return '1-10';
268→    if (count <= 50) return '11-50';
269→    if (count <= 200) return '51-200';
270→    return '200+';
271→  } catch {
272→    return 'unknown';
273→  }
274→}
