286→/**
287→ * Check if code-insights is registered as a Claude Code hook.
288→ *
289→ * Reads ~/.claude/settings.json and looks for 'code-insights' anywhere in the
290→ * file content. A hook registration means the user has automated sync on session end.
291→ */
292→function detectHook(): boolean {
293→  try {
294→    const settingsPath = path.join(os.homedir(), '.claude', 'settings.json');
295→    if (!fs.existsSync(settingsPath)) return false;
296→
297→    const content = fs.readFileSync(settingsPath, 'utf-8');
298→    return content.includes('code-insights');
299→  } catch {
300→    return false;
301→  }
302→}
