304→/**
305→ * Internal: Send the event to the telemetry endpoint.
306→ * AbortController ensures we don't hang longer than 2 seconds.
307→ * All errors are swallowed — telemetry failures must never propagate.
308→ */
309→async function sendEvent(event: TelemetryEvent): Promise<void> {
310→  const controller = new AbortController();
311→  // 2s timeout — enough for a healthy network, short enough to not delay anything
312→  const timer = setTimeout(() => controller.abort(), 2000);
313→
314→  try {
315→    await fetch(TELEMETRY_ENDPOINT, {
316→      method: 'POST',
317→      headers: { 'Content-Type': 'application/json' },
318→      body: JSON.stringify(event),
319→      signal: controller.signal,
320→    });
321→  } catch {
322→    // Swallow everything: network errors, AbortError, JSON serialization errors.
323→    // Telemetry failures are silent — the CLI command already completed.
324→  } finally {
325→    clearTimeout(timer);
326→  }
327→}
